import{_ as t,o as r,c as a,ae as o}from"./chunks/framework.PV3mkH3Y.js";const f=JSON.parse('{"title":"Resource Pack Creation Wiki","description":"","frontmatter":{},"headers":[],"relativePath":"intro.md","filePath":"intro.md"}'),i={name:"intro.md"};function d(n,e,s,l,c,h){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="resource-pack-creation-wiki" tabindex="-1">Resource Pack Creation Wiki <a class="header-anchor" href="#resource-pack-creation-wiki" aria-label="Permalink to &quot;Resource Pack Creation Wiki&quot;">​</a></h1><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>This is the ultimate guide to resource pack creation. From changing textures to custom models, blockstates, entities and more, you&#39;ll become a master at resource pack creation. This guide will have a guide for Optifine and its alternatives.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><p><strong>What is a resource pack?</strong></p><p>A resource pack is a way to change the “assets” loaded into Minecraft. It is a way to change how the game looks, sounds and feels.</p><p><strong>Are resource packs the same as texture packs?</strong></p><p>They are the same but you can only use resource/texture packs in the resource packs folder after the 1.5.2 update.</p><p><strong>Are they hard to make?</strong></p><p>No, they are rather easy to do once you have an understanding of how Minecraft structures its assets folder.</p><p><strong>Do I have to change every texture?</strong></p><p>No, resource packs only change the changed assets in the folder and multiple resource packs can be stacked to create resource pack combos.</p><p><strong>What programs do I need to make a resource pack?</strong></p><p>You don&#39;t need much and can use the preinstalled apps but using apps can make the process of resource pack creation easier.</p><p><strong>So what is a “plain” text editor?</strong></p><p>A plain text editor is a text editor that has no fancy font&#39;s formatting like google docs or microsoft word. Notepad or Notepad++ are plain text editors that are simple to use.</p><h2 id="useful-links" tabindex="-1">Useful Links <a class="header-anchor" href="#useful-links" aria-label="Permalink to &quot;Useful Links&quot;">​</a></h2><p>Here are some links which will be useful or needed to make a resource pack.</p><h2 id="base-texturepack" tabindex="-1">Base Texturepack <a class="header-anchor" href="#base-texturepack" aria-label="Permalink to &quot;Base Texturepack&quot;">​</a></h2><p><a href="https://www.blockbench.net/plugins/asset_browser" target="_blank" rel="noreferrer">Resource Pack Asset Browser</a></p><p>This is how we can get the assets and base texture pack for any version!</p><h2 id="essential-software" tabindex="-1">Essential Software <a class="header-anchor" href="#essential-software" aria-label="Permalink to &quot;Essential Software&quot;">​</a></h2><p>You will need one from each of these catogories to make a resource pack.</p><h3 id="image-editors" tabindex="-1">Image Editors <a class="header-anchor" href="#image-editors" aria-label="Permalink to &quot;Image Editors&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Software</th><th>Price</th><th>OS</th><th>Notes</th></tr></thead><tbody><tr><td>MS paint</td><td>free</td><td>Windows</td><td>no downloads</td></tr><tr><td><a href="https://lospec.com/pixel-editor/app" target="_blank" rel="noreferrer">Lospec Editor</a></td><td>free</td><td>Web-Browser</td><td>no downloads + lospec palette integration</td></tr><tr><td><a href="https://www.pixilart.com/draw" target="_blank" rel="noreferrer">pixilart Editor</a></td><td>free</td><td>Web-Browser</td><td>no downloads</td></tr><tr><td><a href="https://www.getpaint.net/download.html" target="_blank" rel="noreferrer">Paint.NET</a></td><td>free</td><td>Windows</td><td>plugin support</td></tr><tr><td><a href="https://aseprite.org/#buy" target="_blank" rel="noreferrer">Aseprite</a></td><td>$19.99, Free</td><td>Windows, macOS, Linux</td><td>high quality pixel art editor, scripts, themes</td></tr><tr><td><a href="https://www.gimp.org/" target="_blank" rel="noreferrer">GNU image Manipulation Program</a> (GIMP)</td><td>free</td><td>Windows</td><td>-</td></tr><tr><td><a href="https://photoshop.adobe.com/" target="_blank" rel="noreferrer">Photoshop</a></td><td>free, $22.99, $19.99</td><td>Web-Browser, Windows, MacOS</td><td>free on the web for 6 months</td></tr></tbody></table><h3 id="archival-tools" tabindex="-1">Archival Tools <a class="header-anchor" href="#archival-tools" aria-label="Permalink to &quot;Archival Tools&quot;">​</a></h3><p>Needed to unzip the Minecraft jar file and to zip your pack when it is done.</p><table tabindex="0"><thead><tr><th>Software</th><th>Price</th><th>OS</th><th>Notes</th></tr></thead><tbody><tr><td><a href="https://www.7-zip.org/" target="_blank" rel="noreferrer">7-Zip</a></td><td>free</td><td>Windows, linux</td><td>-</td></tr><tr><td><a href="https://www.win-rar.com/" target="_blank" rel="noreferrer">WinRAR</a></td><td>free, paid</td><td>Windows, macOS, Linux</td><td>unlimited free trial</td></tr></tbody></table><h3 id="text-editor" tabindex="-1">Text Editor <a class="header-anchor" href="#text-editor" aria-label="Permalink to &quot;Text Editor&quot;">​</a></h3><p>Used to edit the text files in your pack.</p><table tabindex="0"><thead><tr><th>Software</th><th>Price</th><th>OS</th><th>Notes</th></tr></thead><tbody><tr><td><a href="https://code.visualstudio.com/" target="_blank" rel="noreferrer">Visual Studio Code</a></td><td>free</td><td>windows, mac, linux</td><td>open source</td></tr><tr><td><a href="https://notepad-plus-plus.org/" target="_blank" rel="noreferrer">notepad++</a></td><td>free</td><td>windows</td><td>beginner friendly</td></tr><tr><td><a href="https://code.visualstudio.com/" target="_blank" rel="noreferrer">Visual Studio Code</a></td><td>free</td><td>windows, mac, linux</td><td>built on top of open source</td></tr><tr><td><a href="https://vscodium.com/" target="_blank" rel="noreferrer">VSCodium</a></td><td>free</td><td>window, linux</td><td>open source binaries for vscode</td></tr></tbody></table><h3 id="useful-software" tabindex="-1">Useful software <a class="header-anchor" href="#useful-software" aria-label="Permalink to &quot;Useful software&quot;">​</a></h3><p>Depending on what you want to include in your pack, a program from the relevant category may be needed, or at least save a lot of frustration.</p><table tabindex="0"><thead><tr><th>Software</th><th>About</th></tr></thead><tbody><tr><td><a href="https://blockbench.net/" target="_blank" rel="noreferrer">Blockbench</a></td><td>A free program to create 3d models for Minecraft and similar games.</td></tr><tr><td><a href="https://mrcrayfish.com/tools?id=mc#downloads" target="_blank" rel="noreferrer">Mr. Crayfish’s Model Creator</a></td><td>An alternative program for creating 3d Minecraft models.</td></tr></tbody></table><h3 id="texture-resource-pack-converters" tabindex="-1">Texture/Resource Pack Converters <a class="header-anchor" href="#texture-resource-pack-converters" aria-label="Permalink to &quot;Texture/Resource Pack Converters&quot;">​</a></h3><p>Tools to convert texture &amp; resource packs to newer versions.</p><table tabindex="0"><thead><tr><th>Software</th><th>About</th></tr></thead><tbody><tr><td><a href="http://assets.minecraft.net/unstitcher/unstitcher.jar" target="_blank" rel="noreferrer">Dinnerbone&#39;s Texture Pack Unstitcher Program (Direct Download)</a></td><td>A tool to convert texture packs to Minecraft version 1.5.</td></tr><tr><td><a href="https://github.com/flying-sheep/unstitcher/" target="_blank" rel="noreferrer">Flying-Sheep&#39;s Texture Pack Unstitcher Rewrite</a></td><td>A rewrite of Dinnerbone&#39;s tool made by a community member.</td></tr><tr><td><a href="http://s3.amazonaws.com/Minecraft.Download/utilities/TextureEnder.jar" target="_blank" rel="noreferrer">TextureEnder made by Mojang (Direct Download)</a></td><td>A tool made by Mojang to convert Texture Packs from 1.5 to resource packs. (also on GitHub)</td></tr><tr><td><a href="https://www.planetminecraft.com/mod/minecraft-1-12-1-13-1-14-1-15-resource-pack-converter/" target="_blank" rel="noreferrer">Resource Pack Converter</a></td><td>A tool to convert resource packs to newer versions.</td></tr><tr><td><a href="https://ozelot379.github.io/ConvertJavaTextureToBedrock/" target="_blank" rel="noreferrer">Java to Bedrock Resource Pack Converter</a></td><td>A tool to convert your java resource pack to bedrock.</td></tr></tbody></table><h3 id="other-software" tabindex="-1">Other Software <a class="header-anchor" href="#other-software" aria-label="Permalink to &quot;Other Software&quot;">​</a></h3><p>Not always needed, but useful to have sometimes.</p><table tabindex="0"><thead><tr><th>Software</th><th>About</th></tr></thead><tbody><tr><td><a href="https://github.com/PCelestia/optimise-resourcepack" target="_blank" rel="noreferrer">Resource Pack Optimizer</a></td><td>An optimization tool that compresses the image files to save space.</td></tr><tr><td><a href="https://github.com/DeflatedPickle/Quiver" target="_blank" rel="noreferrer">Quiver</a></td><td>A resource pack creator and manager for Minecraft.</td></tr><tr><td><a href="https://winmerge.org/?lang=en" target="_blank" rel="noreferrer">WinMerge</a></td><td>A useful tool to compare your pack to default Minecraft and see what you&#39;re missing and what files are the same as default to remove them.</td></tr><tr><td><a href="https://github.com/Ravbug/MCSoundsExtractorCPP" target="_blank" rel="noreferrer">Minecraft Sound Extractor</a></td><td>This is for extracting the sound if you want to see how to structure the sound directory in your resource pack.</td></tr></tbody></table><h2 id="information-and-resources" tabindex="-1">Information and Resources <a class="header-anchor" href="#information-and-resources" aria-label="Permalink to &quot;Information and Resources&quot;">​</a></h2><p>A collection of useful info and resources.</p><h3 id="minecraft-wiki" tabindex="-1">Minecraft Wiki <a class="header-anchor" href="#minecraft-wiki" aria-label="Permalink to &quot;Minecraft Wiki&quot;">​</a></h3><p>Useful Minecraf Wiki pages.</p><table tabindex="0"><thead><tr><th>Minecraft Wiki Page Title</th><th>Description</th></tr></thead><tbody><tr><td><a href="https://minecraft.gamepedia.com/Resource_Pack" target="_blank" rel="noreferrer">Wiki Page: Resource Packs</a></td><td>The official wiki on Minecraft resource packs, updated regularly per update/snapshot, documenting changes between versions.</td></tr><tr><td><a href="https://minecraft.gamepedia.com/Tutorials/Creating_a_resource_pack" target="_blank" rel="noreferrer">Wiki Page: Creating a Resource Pack</a></td><td>Will be updated regularly per update/snapshot, documenting changes between versions.</td></tr><tr><td><a href="https://minecraft.gamepedia.com/Texture_Pack" target="_blank" rel="noreferrer">Wiki Page: Texture Packs</a></td><td>Useful information on texture packs for Minecraft versions 1.6.0 and newer.</td></tr><tr><td><a href="https://minecraft.gamepedia.com/Tutorials/Custom_texture_packs" target="_blank" rel="noreferrer">Wiki Page: Creating a Texture Pack</a></td><td>Has useful info on making texture packs for Minecraft 1.6.0 and older.</td></tr><tr><td><a href="https://minecraft.gamepedia.com/Formatting_codes" target="_blank" rel="noreferrer">Wiki Page: Formatting codes</a></td><td>Useful reference when editing text files such as pack.mcmeta and credits.txt.</td></tr><tr><td><a href="https://minecraft.gamepedia.com/Model" target="_blank" rel="noreferrer">Wiki Page: Models</a></td><td>Has a lot of useful info about blockstates and model files.</td></tr><tr><td><a href="https://minecraft.gamepedia.com/Tint" target="_blank" rel="noreferrer">Wiki Page: Tint</a></td><td>Useful info about the grass and foliage color tinting.</td></tr></tbody></table><h3 id="other-guides" tabindex="-1">Other Guides <a class="header-anchor" href="#other-guides" aria-label="Permalink to &quot;Other Guides&quot;">​</a></h3><p>an assortment of other guides with a lot of useful information in them. Title | About | Type –|–|– <a href="https://www.minecraftforum.net/forums/mapping-and-modding-java-edition/resource-packs/resource-pack-discussion/1256365-a-word-about-texturepacks" target="_blank" rel="noreferrer">A word about texture packs</a>|A good read about myths surrounding texture/resource packs.|Minecraft Forums Thread <a href="https://www.minecraftforum.net/forums/mapping-and-modding-java-edition/resource-packs/resource-pack-discussion/1256350-animation-in-resource-packs-a-minecraft-1-6" target="_blank" rel="noreferrer">Animation in Resource Packs</a>|A useful guide on animated block and item textures.|Minecraft Forums Thread <a href="https://www.minecraftforum.net/forums/mapping-and-modding-java-edition/resource-packs/resource-pack-discussion/2209236-1-8-tutorial-alternate-textures-and-custom-models" target="_blank" rel="noreferrer">Making Alternate Textures Guide</a>|A useful guide for variant/alternate textures.|Minecraft Forums Thread <a href="https://www.minecraftforum.net/forums/mapping-and-modding-java-edition/resource-packs/resource-pack-discussion/1256314-the-all-inclusive-guide-to-texturing" target="_blank" rel="noreferrer">The All-Inclusive Guide to Texturing</a>|A helpful guide to making texture packs, mostly useful for older versions of Minecraft before 1.5.|Minecraft Forums Thread <a href="https://www.minecraftforum.net/forums/mapping-and-modding-java-edition/resource-packs/resource-pack-discussion/1256366-the-all-inclusive-updated-guide-to-texturing" target="_blank" rel="noreferrer">The All-Inclusive Guide to Texturing (Version 2)</a>|An updated version that has useful information on newer versions of Minecraft.|Minecraft Forums Thread <a href="https://www.youtube.com/playlist?list=PLLl4D8G2NepWULG7fqAeBvpd1SOtP7pe8" target="_blank" rel="noreferrer">How To Make A Resource Pack video series by Uncle Jam</a>|A good playlist of videos about making a resource pack. (Has a lot of useful info in it, just please do not copy the default Minecraft assets folder like he does. See common mistakes below.)|Youtube Video Playlist <a href="https://www.youtube.com/playlist?list=PLfp-NJt_DpgG2odTDbwjtXkdjdBgpSxng" target="_blank" rel="noreferrer">Customizing Minecraft video series by How To Gurus</a>|A great playlist with a lot of useful guides for making a resource pack.|Youtube Video Playlist</p><h3 id="other-documentation" tabindex="-1">Other Documentation <a class="header-anchor" href="#other-documentation" aria-label="Permalink to &quot;Other Documentation&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Documentation</th><th>About</th></tr></thead><tbody><tr><td><a href="https://github.com/sp614x/optifine/tree/master/OptiFineDoc/doc" target="_blank" rel="noreferrer">Optifine Documentation</a></td><td>The official documentation for Optifine, use it if you want advanced help on some of the features optifine provides for us!</td></tr></tbody></table><h2 id="places-to-find-help-and-submit-your-pack" tabindex="-1">Places to find help and submit your pack <a class="header-anchor" href="#places-to-find-help-and-submit-your-pack" aria-label="Permalink to &quot;Places to find help and submit your pack&quot;">​</a></h2><p>Good places to go if you need help or want to submit your pack to be seen by the public.</p><table tabindex="0"><thead><tr><th>Place</th><th>About</th></tr></thead><tbody><tr><td><a href="https://modrinth.com/" target="_blank" rel="noreferrer">Modrinth</a></td><td>The number 1 place for minecraft content like resource packs.</td></tr><tr><td><a href="https://www.curseforge.com/minecraft" target="_blank" rel="noreferrer">Curseforge</a></td><td>The older but still popular alternative to Modrinth</td></tr><tr><td><a href="https://www.planetminecraft.com/texture-packs/" target="_blank" rel="noreferrer">Planet Minecraft</a></td><td>A good place to ask for help or post your pack.</td></tr></tbody></table><h2 id="useful-keybinds" tabindex="-1">Useful Keybinds <a class="header-anchor" href="#useful-keybinds" aria-label="Permalink to &quot;Useful Keybinds&quot;">​</a></h2><p>Here are some useful key binds I will mention in this guide!</p><h3 id="minecraft" tabindex="-1">Minecraft <a class="header-anchor" href="#minecraft" aria-label="Permalink to &quot;Minecraft&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Action</th><th>Keybind</th></tr></thead><tbody><tr><td>F3 + T</td><td>Reload resources</td></tr><tr><td>F3 + D</td><td>Clear Chat logs</td></tr><tr><td>F1</td><td>Toggle UI visiblity</td></tr></tbody></table><h3 id="gimp" tabindex="-1">GIMP <a class="header-anchor" href="#gimp" aria-label="Permalink to &quot;GIMP&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Action</th><th>Keybind</th></tr></thead><tbody><tr><td>Pencil</td><td>N</td></tr><tr><td>Undo</td><td>Ctrl + Z</td></tr><tr><td>Redo</td><td>Ctrl + Y</td></tr><tr><td>Zoom</td><td>Ctrl + mouse wheel in and out</td></tr><tr><td>Color picker</td><td>Ctrl + primary mouse click (only works when pencil/paintbrush is the selected tool)</td></tr><tr><td>Pan</td><td>Hold the spacebar and drag the mouse.</td></tr></tbody></table><h3 id="paint-net" tabindex="-1">Paint.NET <a class="header-anchor" href="#paint-net" aria-label="Permalink to &quot;Paint.NET&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Action</th><th>Keybind</th></tr></thead><tbody><tr><td>Pencil</td><td>P</td></tr><tr><td>Line Tool</td><td>O</td></tr><tr><td>Pan</td><td>Hold the spacebar and left click and drag (alternatively press H to select the pan tool)</td></tr><tr><td>Color picker</td><td>K</td></tr><tr><td>Eraser</td><td>E</td></tr><tr><td>Paint Bucket</td><td>F</td></tr><tr><td>Shape tool</td><td>O, O (press O twice)</td></tr></tbody></table><h2 id="helpful-advice" tabindex="-1">Helpful Advice <a class="header-anchor" href="#helpful-advice" aria-label="Permalink to &quot;Helpful Advice&quot;">​</a></h2><h3 id="general-advice" tabindex="-1">General Advice <a class="header-anchor" href="#general-advice" aria-label="Permalink to &quot;General Advice&quot;">​</a></h3><p>Here are some quick advice:</p><ul><li>Keep to one resolution like 16x16, or 32x32. Don&#39;t mix and match resolutions.</li><li>If you want your resource pack to look nice with your builds that look good in vanilla, use a similar colour palette.</li></ul><h3 id="common-mistakes" tabindex="-1">Common mistakes <a class="header-anchor" href="#common-mistakes" aria-label="Permalink to &quot;Common mistakes&quot;">​</a></h3><p>Here are some common mistakes to avoid while making your texture pack.</p><ul><li>Do not copy all the minecraft assets, copy the folder structure and add your made textures.</li><li>Make sure all the files are in the right place and named correctly.</li></ul>',67)])])}const p=t(i,[["render",d]]);export{f as __pageData,p as default};
